import{_ as i,a as n}from"./-R-54xPY.js";import{d as r,T as o,c as l,l as s,f as d,o as p}from"./Cgg9BBel.js";import"./DPDyFnUs.js";const c={class:"font-sans"},b=r({__name:"confidentialite",setup(m){return o({title:"Politique de confidentialité — Faso Agri",description:"Politique de confidentialité de l'application Faso Agri, développée par Faso Agri.",ogImage:"/images/logo.png"}),(u,e)=>{const t=i,a=n;return p(),l("div",c,[s(t),e[0]||(e[0]=d('<main class="max-w-3xl mx-auto px-6 pt-32 pb-20"><div class="mb-10"><div class="text-6xl font-semibold text-primary uppercase tracking-wider mb-3"> Faso Agri </div><h1 class="text-4xl font-semibold text-gray-900 mb-3">Politique de confidentialité</h1><p class="text-sm text-gray-400">Dernière mise à jour : janvier 2026</p></div><div class="space-y-10"><section><p class="text-gray-600 leading-relaxed text-sm"> La présente politique de confidentialité décrit la manière dont Faso Agri, développée par Faso Agri, collecte, utilise et protège les informations personnelles des utilisateurs de l&#39;application mobile Faso Agri (ci-après « l&#39;Application »). Nous nous engageons à protéger votre vie privée et à traiter vos données personnelles avec transparence. </p></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 1. Données collectées </h2><p class="text-gray-600 text-sm mb-3"> Dans le cadre de l&#39;utilisation de l&#39;Application, nous sommes susceptibles de collecter les catégories de données suivantes : </p><ul class="space-y-2"><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Informations d&#39;identification : nom, prénom, numéro de téléphone, adresse e-mail. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Données de localisation : région et ville renseignées lors de l&#39;inscription, et, avec votre consentement explicite, votre position GPS pour afficher des contenus proches de vous. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Données de profil : type d&#39;activité (producteur, éleveur, acheteur, professionnel), photos de profil et d&#39;annonces. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Données d&#39;utilisation : interactions avec l&#39;Application, annonces consultées ou publiées, événements enregistrés. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Données techniques : identifiant de l&#39;appareil, version du système d&#39;exploitation, logs d&#39;erreurs. </li></ul></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 2. Finalités du traitement </h2><p class="text-gray-600 text-sm mb-3"> Les données collectées sont utilisées pour les finalités suivantes : </p><ul class="space-y-2"><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Création et gestion de votre compte utilisateur. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Affichage et gestion des annonces du marché agricole. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Mise en relation entre acteurs de la chaîne de valeur agro-pastorale. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Affichage de l&#39;annuaire des professionnels et des événements agricoles. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Amélioration continue de l&#39;Application et de ses fonctionnalités. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Envoi de notifications liées à votre activité sur l&#39;Application (avec votre consentement). </li></ul></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 3. Base légale du traitement </h2><p class="text-gray-600 leading-relaxed text-sm"> Le traitement de vos données personnelles repose sur les bases légales suivantes : l&#39;exécution du contrat d&#39;utilisation de l&#39;Application lors de la création de votre compte, votre consentement pour les traitements facultatifs tels que la géolocalisation précise et les notifications, et notre intérêt légitime à améliorer la qualité et la sécurité de nos services. </p></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 4. Partage des données </h2><p class="text-gray-600 text-sm mb-3"> Faso Agri ne vend ni ne loue vos données personnelles à des tiers. Vos données peuvent être partagées dans les cas suivants : </p><ul class="space-y-2"><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Avec les autres utilisateurs de l&#39;Application, dans la limite des informations que vous avez choisies de rendre publiques (nom, région, annonces publiées). </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Avec nos prestataires techniques (hébergement Firebase / Google Cloud) dans le cadre de l&#39;exploitation de l&#39;Application, sous contrat de confidentialité. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> En cas d&#39;obligation légale ou de réquisition judiciaire. </li></ul></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 5. Durée de conservation </h2><p class="text-gray-600 leading-relaxed text-sm"> Vos données personnelles sont conservées pendant toute la durée d&#39;activité de votre compte. En cas de suppression de votre compte, vos données sont supprimées dans un délai de 30 jours, à l&#39;exception des données devant être conservées en vertu d&#39;une obligation légale. </p></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 6. Sécurité des données </h2><p class="text-gray-600 leading-relaxed text-sm mb-3"> Nous mettons en œuvre des mesures techniques et organisationnelles appropriées pour protéger vos données contre tout accès non autorisé, perte, destruction ou divulgation. L&#39;accès aux données est strictement limité aux personnes habilitées au sein de Faso Agri. </p><p class="text-gray-600 leading-relaxed text-sm"> Les données sont hébergées sur les infrastructures sécurisées de Google Firebase, conformément aux standards internationaux de sécurité. </p></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 7. Vos droits </h2><p class="text-gray-600 text-sm mb-3"> Conformément à la réglementation applicable en matière de protection des données personnelles, vous disposez des droits suivants : </p><ul class="space-y-2"><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Droit d&#39;accès : obtenir une copie des données personnelles vous concernant. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Droit de rectification : corriger des données inexactes ou incomplètes. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Droit à l&#39;effacement : demander la suppression de vos données personnelles. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Droit d&#39;opposition : vous opposer à certains traitements de vos données. </li><li class="flex items-start gap-2 text-sm text-gray-600"><span class="w-1.5 h-1.5 rounded-full bg-primary mt-2 flex-shrink-0"></span> Droit à la portabilité : recevoir vos données dans un format structuré. </li></ul></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 8. Cookies et technologies similaires </h2><p class="text-gray-600 leading-relaxed text-sm"> L&#39;Application mobile Faso Agri n&#39;utilise pas de cookies au sens strict. Des identifiants techniques propres à votre appareil peuvent être utilisés à des fins d&#39;analyse d&#39;utilisation anonyme et d&#39;amélioration de l&#39;expérience utilisateur. </p></section><section><h2 class="text-lg font-semibold text-gray-900 mb-3 pb-2 border-b border-gray-100"> 9. Modifications de la politique </h2><p class="text-gray-600 leading-relaxed text-sm mb-3"> Nous nous réservons le droit de modifier la présente politique de confidentialité à tout moment. En cas de modification substantielle, vous serez informé via une notification dans l&#39;Application ou par e-mail. La date de dernière mise à jour figurant en haut de ce document sera actualisée en conséquence. </p><p class="text-gray-600 leading-relaxed text-sm"> Nous vous encourageons à consulter régulièrement cette page pour rester informé de nos pratiques en matière de protection des données. </p></section></div></main>',1)),s(a)])}}});export{b as default};
